static void secure_clear(char *buf, size_t len) {
    if (buf && len > 0) {
        volatile char *p = (volatile char *)buf;
        while (len--) {
            *p++ = 0;
        }
    }
}

static char *load_env_required(const char *var_name) {
    const char *value = getenv(var_name);
    if (value == NULL || strlen(value) == 0) {
        fprintf(stderr, "ERROR: Required environment variable '%s' is not set.\n", var_name);
        fprintf(stderr, "Please set it before running this application.\n");
        fprintf(stderr, "Example: export %s=\"<value>\"\n", var_name);
        return NULL;
    }
    /* Return a copy so we can securely clear it later */
    char *copy = strdup(value);
    return copy;
}

static const char *load_env_with_default(const char *var_name, const char *default_value) {
    const char *value = getenv(var_name);
    if (value == NULL || strlen(value) == 0) {
        return default_value;
    }
    return value;
}

